import{_ as a,o as d,c as r,ak as e}from"./chunks/framework.B_unCYUt.js";const b=JSON.parse('{"title":"职场管理","description":"","frontmatter":{},"headers":[],"relativePath":"Courses/职场管理.md","filePath":"Courses/职场管理.md","lastUpdated":1708868588000}'),p={name:"Courses/职场管理.md"};function n(h,t,o,s,l,i){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="职场管理" tabindex="-1">职场管理 <a class="header-anchor" href="#职场管理" aria-label="Permalink to “职场管理”">​</a></h1><p>代表对工作的认可, 制度是公司正常运行的重要保证, 不能跨越这个底线</p><p>突出的点: <code>技术知识</code>, <code>工具相关知识</code>, <code>职业素养</code></p><h1 id="职业规划" tabindex="-1">职业规划 <a class="header-anchor" href="#职业规划" aria-label="Permalink to “职业规划”">​</a></h1><p>Python + Go 作为主要开发语言: 分别重效率, 重工程</p><p>C++ / JAVA 可理解程序, 懂核心思想 , 进行轻度开发 , 不要作为主要语言</p><h1 id="学历提升的意义" tabindex="-1">学历提升的意义 <a class="header-anchor" href="#学历提升的意义" aria-label="Permalink to “学历提升的意义”">​</a></h1><p>不只是提升学历, 还有圈子和层次和人脉</p><p><u>财富和社会地位的双重加成</u></p><p><strong>会获得更多的机会</strong></p><p>社会对于高学历的优厚待遇</p><p>工作经验和技术可以弥补学历上的不足</p><h1 id="自考" tabindex="-1">自考 <a class="header-anchor" href="#自考" aria-label="Permalink to “自考”">​</a></h1><p>080901</p><p>计算机科学与技术 080901 - 上海交大</p><p>计算机及应用 - 2080702 - 南京大学/ 南京航天航空</p><p>报考时间 : 2019 年3月份</p><p>优先参考 <a href="http://www.shmeea.edu.cn/page/04000/index.html" target="_blank" rel="noreferrer">上海招考热线</a></p><h2 id="解决问题思路" tabindex="-1">解决问题思路 <a class="header-anchor" href="#解决问题思路" aria-label="Permalink to “解决问题思路”">​</a></h2><p>看官网</p><p>咨询学校的相关部门负责人</p><p>自考：学习方法因人而异：供参考 根据每次的考试科目安排选好自己即将要考试的科目，比如4月份能考4门，就把时间放在这4门上面，其他的科目可以暂时不用管，集中精力去学习（平时是看课本，做个笔记本，积少成多，考前多做练习）12月~3月份把课本熟练的学2/3遍，4月份多总结，自考是需要坚持的</p><h2 id="重要提醒" tabindex="-1">重要提醒 <a class="header-anchor" href="#重要提醒" aria-label="Permalink to “重要提醒”">​</a></h2><p>学位英语 是必须的</p><p>凡取得全国公共英语等级考试三级（PETS—3）笔试合格成绩的考生，在参加自学考试时，可申请免考公共外语英语（二）（代码0015），并获得相应学分。</p><h2 id="相关政策" tabindex="-1">相关政策 <a class="header-anchor" href="#相关政策" aria-label="Permalink to “相关政策”">​</a></h2><h2 id="专业介绍" tabindex="-1">专业介绍 <a class="header-anchor" href="#专业介绍" aria-label="Permalink to “专业介绍”">​</a></h2><p><a href="https://ce.sjtu.edu.cn/ste/specialty/intro/B080702.htm" target="_blank" rel="noreferrer">官方介绍</a></p><p><strong>升本专业编号080901：</strong></p><p>本专业由上海交通大学主考，是面向社会开考专业。</p><p>本专业为专升本学历层次。</p><p><strong>专业要求：</strong>系统的掌握计算机软件、硬件的基础理论知识；具有计算机应用系统的分析、设计、实现及维护的知识与技能；具有阅读本专业外文资料的能力。</p><p><strong>报考本专业专升本的条件：</strong> (1)各类本科及以上毕业生和理工科类专科毕业生可直接报考本专业（专升本）。 (2)其他专业专科毕业生报考本专业（专升本）时，须加考“计算机组成原理”（课程代码：2318，4学分）和“电子技术基础（三）”（课程代码：4730、4731，7学分）两门课程。</p><table tabindex="0"><thead><tr><th>序 号</th><th>课程代码</th><th>课 程 名 称</th><th>学 分</th><th>备 注</th></tr></thead><tbody><tr><td>-1</td><td>2318</td><td>计算机组成原理</td><td>4</td><td></td></tr><tr><td>0</td><td>4730,4731</td><td>电子技术基础(三)</td><td>7</td><td></td></tr><tr><td>1</td><td>3708</td><td>中国近现代史纲要</td><td>2</td><td></td></tr><tr><td>2</td><td>3709</td><td>马克思主义基本原理概论</td><td>4</td><td></td></tr><tr><td>3</td><td>15</td><td>英语(二)</td><td>14</td><td></td></tr><tr><td>4</td><td>23</td><td>高等数学（工本）</td><td>10</td><td></td></tr><tr><td>5</td><td>2197</td><td>概率论与数理统计(二)</td><td>3</td><td></td></tr><tr><td>6</td><td>2324</td><td>离散数学</td><td>4</td><td></td></tr><tr><td>7</td><td>2331</td><td>数据结构</td><td>5</td><td>含实验考核(4734)2学分</td></tr><tr><td>8</td><td>4735</td><td>数据库系统原理</td><td>6</td><td>含实验考核(4736)2学分</td></tr><tr><td>9</td><td>2325</td><td>计算机系统结构</td><td>4</td><td></td></tr><tr><td>10</td><td>2326</td><td>操作系统</td><td>5</td><td>含实验考核(2327)1学分</td></tr><tr><td>11</td><td>4737</td><td>C++程序设计</td><td>5</td><td>含实验考核(4738)2学分</td></tr><tr><td>12</td><td>4747</td><td><strong>Java语言程序设计(一)</strong></td><td>4</td><td>含实验考核(4748)1学分</td></tr><tr><td>13</td><td>2333</td><td><strong>软件工程</strong></td><td>4</td><td>含实验考核(2334)1学分</td></tr><tr><td>14</td><td>4741</td><td>计算机网络原理</td><td>4</td><td></td></tr><tr><td>15</td><td>10203</td><td>毕业设计</td><td></td><td>不计学分</td></tr><tr><td>合计</td><td></td><td></td><td>74</td><td>14门课程(不含毕业设计)</td></tr></tbody></table><h2 id="书籍购买" tabindex="-1">书籍购买 <a class="header-anchor" href="#书籍购买" aria-label="Permalink to “书籍购买”">​</a></h2><p>京东 天猫 使用 <strong>课程代码和课程名称</strong> 进行条件搜索 或者 <strong>自考通</strong> / <strong>博益网</strong></p><p><a href="D:%5Cwwfyde%5C%E5%AD%A6%E5%8E%86%E6%8F%90%E5%8D%87%5C2020%E5%B9%B44%E6%9C%88%E8%80%83%E7%BA%B2%E4%B9%A6%E7%9B%AE.pdf" target="_blank" rel="noreferrer">参考课程</a></p><table tabindex="0"><thead><tr><th>2020年4月上海市高等教育自学考试全国统考课程教材考纲书目表</th><th></th><th></th><th></th><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td>课程代码</td><td>课程名称</td><td>学分</td><td>教材名称（含考纲）</td><td>主编</td><td>出版社</td><td>版次</td><td></td></tr><tr><td>00015</td><td>英语(二)(00015)</td><td>14</td><td>英语(二)自学教程</td><td>张敬源 张 虹</td><td>外语教学与研究出版社</td><td>2012年版</td><td></td></tr><tr><td>03708</td><td>中国近现代史纲要(03708)</td><td>2</td><td>中国近现代史纲要</td><td>本书编写组</td><td>高等教育出版社</td><td>2018年版</td><td>中国近现代史纲要自学考试学习读本</td></tr><tr><td>03709</td><td>马克思主义基本原理概论(03709)</td><td>4</td><td>马克思主义基本原理概论</td><td>本书编写组</td><td>高等教育出版社</td><td>2018年版</td><td>马克思主义基本原理概论自学考试学习读本</td></tr></tbody></table><h2 id="自考流程" tabindex="-1">自考流程 <a class="header-anchor" href="#自考流程" aria-label="Permalink to “自考流程”">​</a></h2><p>自考流程：</p><p>1、确定专业和学校<a href="http://www.shzkw.org/shzkzy/%EF%BC%88%E5%B8%B8%E8%A7%84%E5%92%8C%E4%BC%98%E5%8A%BF%E4%B8%93%E4%B8%9A%E5%8F%AF%E4%BB%A5%E6%8A%A5%E8%80%83%EF%BC%89" target="_blank" rel="noreferrer">http://www.shzkw.org/shzkzy/（常规和优势专业可以报考）</a> 2、根据考试安排、结合自身能力选择几门课程买书复习（考试安排和自考参考用书一般考前四个月公布，未公布的话可以先参考历年考试安排和教材）</p><p>3、按时报名课程考试：上海自考报名时间在2月份和9月份，2月份报考的4月份考试，9月份报考的，10月份考试。 4、考前一周打印准考证：具体考点、考试时间都在准考证上面 5、按照准考证时间按时参加考试。 6、考后一个月时间查询考试成绩。合格的历史成绩博益网查询：<a href="http://www.boeebook.cn/article/show/166" target="_blank" rel="noreferrer">http://www.boeebook.cn/article/show/166</a> 7、进行下次自考复习备考，重复2-6的环节 8、如此循环直到全部课程考试通过，即可申请毕业证。</p><h2 id="报名时间" tabindex="-1">报名时间 <a class="header-anchor" href="#报名时间" aria-label="Permalink to “报名时间”">​</a></h2><p>2019 2/21-3/3</p><p>网上报名(不需要去现场确认), 现场考试, 报名时间在三月和九月, 考试时间在四月和十月, 提前准备考试</p><h2 id="考试安排" tabindex="-1">考试安排 <a class="header-anchor" href="#考试安排" aria-label="Permalink to “考试安排”">​</a></h2><blockquote><p>需要在网上查</p></blockquote><p>有的科目是市里统考 有的是全国统考</p><p>高数 概率论 中国近代史 马克思主义</p><table tabindex="0"><thead><tr><th>计算机科学与技术专业 080901 （专升本）</th><th>*(02324)离散数学 *(02318)计算机组成原理（J） *<strong>(03708)中国近现代史纲要</strong></th><th><em>(02326)操作系统 <br></em>(04735)数据库系统原理 <br>*(04730)电子技术基础（三）（J） *(03709)<strong>马克思主义基本原理概论</strong></th><th>*(02197)概率论与数理统计 （二） ***(02325)计算机系统结构</th><th><br>(00023)高等数学（工本） <br>(04741)计算机网络原理**</th></tr></thead><tbody><tr><td>科学与技术专业 080901 （专升本）2019年</td><td>*(02331)数据结构 *(04747)Java 语言程序设计（一） *(03709)马克思主义基本原理概论</td><td>*(00023)高等数学（工 本）</td><td>*(04737)C++程序设计 *(03708)中国近现代史纲要</td><td>*(02333)软件工程 *(00015)英语（二）</td></tr></tbody></table><h2 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to “联系方式”">​</a></h2><p>上海交通大学(徐汇校区) 地址：上海市华山路1954号</p><p>上海交通大学自考专业培训报名电话：021-51602254</p><p>联系地址:法华镇路535号主楼(安泰教学楼) 309室，邮编: 200052 版权所有:上海交通大学继续教育学院</p><h2 id="课程考试规划" tabindex="-1">课程考试规划 <a class="header-anchor" href="#课程考试规划" aria-label="Permalink to “课程考试规划”">​</a></h2><blockquote><p>需要调整 因为 一周只能考4门</p></blockquote><ul><li>先学基础理论 和 C++, 再学JAVA</li></ul><p>第一个月 先考试简单的, 先易后难, 使用同质性的</p><p>一期 最多只能考4门 然后一年两期</p><p><s>202004 <strong>计算机组成原理</strong> 02318 2016</s>,</p><p><strong>02325 计算机系统结构</strong></p><p><strong>(04741)计算机网络原理</strong></p><p><s><strong>英语(二)</strong> 00015 2012,</s> 据说过了pets3 可以免考英语二</p><p><strong>马克思主义基本原理概论</strong>03709 2018,</p><p><strong>中国近代史纲要</strong> 03708 2018版</p><h2 id="刷题" tabindex="-1">刷题 <a class="header-anchor" href="#刷题" aria-label="Permalink to “刷题”">​</a></h2><p>自考网中有试题</p><h2 id="英语二" tabindex="-1">英语二 <a class="header-anchor" href="#英语二" aria-label="Permalink to “英语二”">​</a></h2><p>自考英语二的题型如下： Part one(50’) 1、Vocabulary andstructure（10’） 2、Cloze（10’） 3、Reading comprehension（30’） Part two(50’) 1、Word spelling(10’) 2、Word form(10’) 3、 Translation fromChinese into English(15’) 4、Translation from English into Chinese(15’) 和其他的英语考试相比，没有听力和作文。下面是各种题型的考点及要点：</p><p>1、Vocabulary andstructure（10’）</p><p>主要考点：词汇辨析；固定搭配；常用句型。 建议：通过学习教材上下册，熟练掌握基本语法，背熟大纲词汇，加强同义词、近义词、和形似词的比较，牢记固定搭配。</p><p>2、Cloze（10’） 完型填空是测试考生语篇理解能力和词汇运用能力的一种综合手段。 考查重点： \\1. 单词及短语的意思及搭配； \\2. 篇章的理解：篇章的意义； 句与句之间的过渡；</p><p>3、Reading comprehension（30’）</p><p>主要特点：文章体裁多为论述文，偶有记叙文，主要涉及文化、教育、风俗、历史、人物故事、社会问题、科普常识等内容，不涉及太专业的内容。文章平均长度为300-350词/篇，总阅读量为1500-2000词。问题以细节题为主，其次是总结题，偶尔有一两道词汇题和推理题。题目的顺序和文章的顺序大体对应。</p><p>4、Word spelling(10’) 单词拼写几乎全部出自下册课文，以A课文为主， 单词长度显著增加，平均词长为9个字母，有5个单词词长超过10个字母，最多出现了两个超纲词</p><p>5、Word form(10’) 熟练掌握动词词形变化规律。注意：动词形式既包括谓语动词的各种形式，如时态、语态及语气（直陈、虚拟）等，虚拟语气为重点，几年来的考题中都有这方面内容；也包括非谓语动词的各种形式。所以做动词的词形变化时，首先要搞清楚它在句中是谓语动词还是非谓语动词，然后再作相应的变化</p><p>6、Translation fromChinese into English(15’)</p><p>a.在翻译每一个句子时，一定要事先筹划：先要想好译成什么样的英语句子结构，是简单句还是复合句，或者是强调句、倒装句。如果选用了复合句，那么要明确哪部分是主句，从句采用的形式，是定语从句、状语从句还是其他的从句。在一个句子内，主语是什么，谓语用什么时态，是主动还是被动，要不要虚拟语气，这些都要事先筹划好。然后动笔进行翻译。</p><p>b.在翻译过程中，有时可能碰到一些<a href="https://www.baidu.com/s?wd=%E8%8B%B1%E8%AF%AD%E5%8D%95%E8%AF%8D&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao" target="_blank" rel="noreferrer">英语单词</a>不会写，这时可以寻找意思相近而自己熟悉的词或词组来代替。对句子的结构同样也可以灵活处理，有些没把握的结构，可以用比较有把握的结构来代替。例如，复合句没有把握，可以用两个简单句来表示；分词做状语没有把握，可以用状语从句来代替等等。</p><p>7、Translation from English into Chinese(15’) a.英语习惯用被动语态，而汉语习惯用主动语态。汉语句子时常没有主语，而英语句子除了个别特殊情况（如祈使句、感叹句）以外，不能没有主语。所以，在翻译时，－定要把握英汉两种语言的不同表达习惯，既要忠实于原文，又要符合汉语的表达习惯。</p><p>b.英语习惯用从句（长句），而汉语习惯用单句（短句）。在考试中要善于运用分译法，用汉语的短句来表达英语长句的内容。</p><p>c.英语习惯用名词表示行为动作，汉语则往往相反。</p><p>因为我们是专门做自考和研究生教育辅导的，所以还比较了解每门课的考试要点的解题方法，上面只是很少的一部分，码字码的累啊，你就将就着看看吧，希望能帮到你，不懂的可以继续问我，加油！</p><h2 id="毕业论文要求" tabindex="-1">毕业论文要求 <a class="header-anchor" href="#毕业论文要求" aria-label="Permalink to “毕业论文要求”">​</a></h2><p><a href="https://ce.sjtu.edu.cn/ste/grad/050610-1.htm" target="_blank" rel="noreferrer">官方文档</a></p><p>**毕业设计报告（论文）撰写的内容与要求 **一份完整的毕业设计报告（论文）应包括以下几方面。</p><p><strong>1.标题</strong> 标题应简短、明确、有概括性。通过标题使读者大致了解毕业设计（论文）的内容、专业的特点和科学的范畴。标题字数要适当，一般不宜超过20字，如果有些细节必须放进标题，为避免冗长，可以分成主标题和副标题，主标题写得简明，将细节放在副标题里。</p><p><strong>2.论文摘要或设计总说明书</strong> 摘要又称内容提要，它应以浓缩的形式概括研究课题的内容、方法和观点，以及取得的成果和结论，应能反映整个内容的精华。中文摘要以300－500字为宜；撰写摘要时应注意以下几点： (1)用精炼、概括的语言来表达，每项内容不宜展开论证或说明； (2)要客观陈述，不宜加主观评价； (3)成果和结论性字句是摘要的重点，在文字论述上要多些，以加深读者的印象； (4)要独立成文，选词用语要避免与全文尤其是前言和结论部分雷同； (5)既要写得简短扼要，又要生动，在词语润色、表达方法和章法结构上要尽可能写得有文彩，以唤起读者对全文阅读的兴趣。 (6)设计总说明主要介绍设计任务来源、设计标准、设计原则及主要技术资料，中文字数要在1500－2000字以内。</p><p><strong>3．目录</strong> 目录按三级标题编写（即：1.……、1.1……、1.1.1……）要求标题层次清晰。目录中标题应与正文中标题一致。</p><p><strong>4．绪论</strong> 应说明本课题的意义、目的、研究范围及要求达到的技术参数；简述本课题应解决的主要问题。</p><p><strong>5． 正文</strong> 正文是作者对研究工作的详细表述。它占全文的绝大部分，其内容包括：问题的提出，研究工作的基本前提、假设和条件；基本概念和理论基础；摸型的建立，实验方案的拟定；基本概念和理论基础；设计计算的方法和内容；实验方法、内容及其分析；理论论证，理论在课题中的应用，课题得出的结果，以及结果的讨论等。学生要根据毕业设计（论文）课题的性质,一般情况下，正文可能仅包含上述的一部分内容。撰写正文部分的具体要求如下所述。  (1)理论分析部分应写明所作的假设及其合理性，所用的分析方法、计算方法、实验方法等那些是他人用过的，那些是自己改进的，那些是自己创造的，以便指导教师审查和纠正，篇幅不宜过多，应以简练的文字概略地表达。 (2)对于用实验方法研究的课题，应具体说明实验用的装置、仪器的性能，并应对所用装置、仪器作出检验和标定。对实验的过程和操作方法，力求叙述简明扼要，对人所共知的内容或细节内容不必详述。对于经理论推导达到研究目的的课题，内容要精心组织，做到概念准确，判断推理符合客观事物的发展规律，符合人们对客观事物的认识习惯，换言之，要做到言之有序，言之有 理，以论点为中心，组成完整而严谨的内容整体。 (3)结果与讨论是全文的心脏，一般要占较多篇幅，在撰写时对必要而充分的数据、现象、认识等要作为分析的依据写进去。在对结果作定性和定量分析时，应说明数据的处理方法以及误差分析，说明现象出现的条件及其可证性，交代理论推导中认识的由来和发展，以便他人以此为依据进行实验验证。对结果进行分析后得出的结论，也应说明其适用的条件与范围。此外，适当运用图、表作为结果与分析，也是科技论文通用的一种表达方式，应精心制作、整洁美观。</p><p><strong>6.结论</strong> 结论包括对整个研究工作进行归纳和综合而得出的总结，还应包括所得结果与已有结果的比较和本课题尚存在的问题，以及进一步开展研究的见解与建议。结论集中反映作者的研究成果，表达作者对所研究的课题的见解，是全文的思想精髓，是文章价值的体现，结论要写得概括、简短。撰写时应注意以下几点。 (1)结论要简洁、明确，措辞应严密，且又容易被人领会； (2)结论应反映个人的研究工作，属于他人已有过的结论要少提； (3)要实事求是地介绍自已研究的成果，切忌言过其实，在无充分把握时应留有余地，因为科学问题的探索是永无止境的。</p><p><strong>7.谢辞</strong> 谢辞应以简短的文字对课题研究与论文撰写过程中曾直接给予帮助的人员(例如指导教师、答疑教师及其他人员)表示自已的谢意，这不仅是一种礼貌，也是对他人劳动的尊重，是治学者应有的思想作风。</p><p><strong>8.参考文献与附录</strong> 参考文献是毕业设计(论文)不可缺少的组成部分，它反映毕业设计(论文)的取材来源、材料的广博程度和材料的可靠程度。一份完整的参考文献也是向读者提供的一份有价值的信息资料。一般做毕业设计(论文)的参考文献不宜过多，但应列入主要的中外文献。 对于一些不宜放入正文中、但作为毕业设计（论文）又不可残缺，的组成部分，或有主要参考价值的内容，可编入毕设计(论文)的附录中，例如，公式的推演、编写的算法语言程序等。如果毕业设计中引用的实例、数据资料，实验结果等符号较多时，为了节约篇幅，便 于读者查阅，可以编写一个符号说明，注明符号代表的意义。附录的篇幅不宜太多，附录一般不要超过正文。</p><p><strong>三、毕业设计（论文）的书写格式</strong> 1. 毕业设计（论文）一律采用国家文字改革委员会正式公布的简化汉字书写，论文一律采用计算机排版、打印（用学校规定的稿纸A4复印纸）。论文要求语句通顺、论述严谨、程序和实验数据完整、齐全、规范、正确。 2.论文内容依次为；中文内封面，包括题目（二号黑体字居中），班级、学生姓名及指导教师姓名等（三号黑体字居中）。中文摘要；题目为三号黑体字居中，“摘要”为四号字体居中。摘要内容为五号宋体字，首行缩进二个字。摘要内容后空一行打印“关键词”（四号黑体字），其后为关键词（四号宋体字），各关键词之间用逗号分开，最后一个关键词后面无标点符号。正文中任何部分不得打印到稿纸边框，稿纸不得随意接长或截短。 正文：正文字数不少于1.5-2万字含设计分析与计算、实验及数据处理、程序等。可分为几章，每章标题为三号黑体字居中，内容为五号字体，首行缩进二个字体。公式应另起一行，公式序号按章节顺序编号。表格按章节顺序编号。插图按章节顺序编号，图中坐标应标注单位。 结论：通常为最后一章，标题为三号黑字体居中，内容为五号宋体，首行缩进二个字。 参考文献：按论文中参考文献出现的次序，用中括号的数字连续编号，依书写次作者、文献名、杂志或书名、卷号或期刊号、出版时间，为五号宋体，首行缩进二个字。 3.标点符号 毕业设计（论文）中标点号应按新闻出版署公布的“标点符号用法”使用。 4.名词、名称 科学技术名词术语尽量采用全国自然科学名词审定委员会公布的规范词或国家标准、部标准中规定的名称，尚未统一规定或叫法有争议的名词术语，可采用惯用的名称。使用外文缩写代替某一名词术语时，首次出现时应在括号内注明其含义，如CPU（Central Processing Unit）代替计算机中央处理器。外国人名一般采用英文原名，可不译成中文，英文人名按名前姓后的原则书写，如P.Cray，不可将外国人姓名中的名部分漏写，例如不能只写Cary, 应写成P.Cray。一般很熟知的外国人名(如牛顿、爱因斯坦、达尔文、马克思等)可按通常标准译 法写译名。 5.量和单位 毕业设计(论文)中的量和单位必须采用中华人民共和国家标准GB3100-GB3102-93，它是以国际单位制(SI)为基础的。非物理量的单位，如件、台、人、元等，可用汉字与符号构成组合形式的单位，例如件/台、元/km。 6.数字 毕业设计(论文)中的测量、统计数据一律用阿拉伯数字，如5.25MeV等。在叙述不很大的数目时，一般不宜用阿拉伯数字。 7.标题层次 毕业设计(论文)的全部标题层次应有条不紊，整齐清晰，相同的层次应采用统一的表示体例，正文中各级标题下的内容应同各自的标题对应，不应有与标题无关的内容。章节编号方法应采用分级阿拉伯数安编号方法，第一级为“1”、“2”、“3”、等， 第二级为“2.1”、“2.2”、“2.3”等，第三级为“2.2.1”、“2.2.2”、“2.2.3”等，但分级阿拉伯数字的编号一般不超过四级，两级之间用下角圆点隔开，除第一级外，其余各级的末尾不加标点。 各层标题均单独占行书写，第一级标题居中书写，第二级标题序数顶格书写，空一格接写标题，末尾不加标点，第三级和第四级标题均空两格书写序数，空一格写标题。第四级以下单独占行的标题须序采用A.B.C.…和a.b.c.两层，标题均空两格书写序数，空一格写标题。正文中对总项包括的分项采用（1）、（2）、（3）…的序号，对分项中的小项采用①、②、③…的序号，数字加半括号或括号后，不再加其他标占点。 8.注释 毕业设计(论文)中有个别名词或情况需要解释时，可加注说明，注释可用页末注(将注文放在加注页稿纸的下端)或篇末注(将全部注文集中在文章末尾)，而不用行中注(夹在正文中的注)。若在同一页中有两个以上的注时，按各注出现的先后，须序编列注号，注释只限于写在注释符号出现的同页，不得隔页。 9.公式 公式应另起一行写在稿纸中央，一行写不完的长公式，最好在等号处转行，如做不到这点，在数学符号(如“+”、“-”号)处转行，数学符号应写在转行后的行首。公式的编号用圆括号括起放在公式右边行末，在公式和编号之间不加虚线，公式可按全文统一编序号，公式序号必须连续，不得重复或跳缺。重复引用的公式不得另编新序号。 公式中分数的横分线要写清楚，特别是连分数(即分子和分母也出现分数时)更要注意分线的长短，并将主要分线和等号对齐。在叙述中也可将分数的分子和分母平列在一行，用斜线分开表述。 10.表格 每个表格应有自已的表题和表序，表题应写在表格上方正中，表序写在表题左方不加标点，空一格接写表题，表题末尾不加标点。全文的表格统一编序，也可以逐章编序，不管采用哪种方式，表序必须连续。表格允许下页接写，接写时表题省略，表头应重复书写，并在右上方写“续表××”。此外，表格应写在离正文首次出现处的近处，不应过分超前或拖后。 11.图 毕业设计(论文)的插图必须精心制作，线条要匀称，图面要整洁美观，插图应与正文呼应，不得与正文脱节。每幅插图应有图序和图题，全文插图可以统一编序，也可以逐章单独编序，不管采用哪种方式，图序必须连续，不得重复或跳缺。由若干分图组成的插图，分图用a,b,c…标序，分图的图名以及图中各种代号的意义，以图注形式写在图题下方，先写分图名，另起行后写代号的意义。图应在描纸或洁白纸上用墨线绘成，或用计算机绘图，电气图或机械图应符合相应的国家标准的要求。</p><h2 id="毕业证学位证申请要求" tabindex="-1">毕业证学位证申请要求 <a class="header-anchor" href="#毕业证学位证申请要求" aria-label="Permalink to “毕业证学位证申请要求”">​</a></h2><p>三、上海交通大学自考本科学士学位申请说明</p><p>根据上海市学位委员会沪学位办[2006]4号文件精神，从2006年起，凡是我校自学考试独立本科段毕业的考生，申请授予学位必须满足以下条件：</p><p>1、申请者必须由本人向交大自考办提出申请;</p><p>2、申请者自学考试本科毕业设计成绩必须中以上(含中) <em>70分以上</em>;</p><p>3、申请者须参加全国大学英语等级(3级)考试(以下简称PETS-3)或在获得本科毕业证书后由本人向上海交通大学自考办提出申请参加毕业当年度一次英语四级考试。2005年6月前英语四、六级合格证书视为有效，所有英语四、六级合格证书，PETS-3考试笔试成绩合格证书，四级考试成绩从获得之日至学士学位申请日期止四年内有效。</p><p>4、对于毕业当年仍未通过<strong>学士学位英语考试要求</strong>者或自己未提出申请学位者，不再补授予学士学位。</p><p>通过专业课程考试且合格后，可获得由上海自考委与上海交通大学联合颁发的自考本科毕业证，符合学士学位申请者通过<strong>论文答辩</strong>与<strong>学位英语</strong>考试，可获得上海交通大学成人高等教育学士学位证书。</p><h2 id="学习顺序" tabindex="-1">学习顺序 <a class="header-anchor" href="#学习顺序" aria-label="Permalink to “学习顺序”">​</a></h2><p>基础</p><p>计算机组成原理</p><h1 id="学习技巧" tabindex="-1">学习技巧 <a class="header-anchor" href="#学习技巧" aria-label="Permalink to “学习技巧”">​</a></h1><h2 id="基本问题" tabindex="-1">基本问题 <a class="header-anchor" href="#基本问题" aria-label="Permalink to “基本问题”">​</a></h2><ul><li>[ ] <u>概念</u>:</li><li>[ ] <u>定义</u>:</li><li>[ ] <u>特征</u>:</li><li>[ ] <u>功能</u>:</li><li>[ ] <u>意义</u>:</li><li>[ ] <u>性质</u>:</li><li>[ ] <u>特性</u>:</li><li>[ ] <u>说明</u>:</li></ul><h1 id="个人信息" tabindex="-1">个人信息 <a class="header-anchor" href="#个人信息" aria-label="Permalink to “个人信息”">​</a></h1><p>您的准考证号为 383020100029。请记录该编号。 　　您报考课程的支付状态只有在支付成功后才能正式生效！点击结算可以支付课程费用，请务必于2020年06月07日17:00之前完成课程费用支付，逾期将无法再进行费用支付。 　　请在2020年07月21日08:30起登录本系统，打印准考证号信息。 　　 2020年上半年（第76次）上海市高等教育自学考试延期考试将于2020年6月2日至6月7日进行网上报名，其中6月2日至6月6日（每天8:30—22:00）接受考生网上报名报考及付费，6月7日8:30—17:00仅接受考生网上付费。 根据目前上海疫情防控要求，为保障考试安全顺利，切实保障广大考生和涉考人员的生命安全和身体健康，提醒各位考生考前14天不要离开上海，提前完成“随申码”申请，必要时需提供考前核酸检测报告，备考期间请做好个人日常防护与健康监测。上海市教育考试院将在考前公布考试实施具体防控要求，请及时关注“上海招考热线”网站（www.shmeea.edu.cn）。</p><h1 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h1><p>1.切记7.21登陆报名页面打印准考证，切记</p><p>2.申请毕业前确认成绩是否满足学位申请条件，毕业申请开始，成绩锁死，不予退回，自考毕业证书落款日起一年内申请学位，预期不再受理（朋友圈有更新学位申请条件）</p><h1 id="零散记录" tabindex="-1">零散记录 <a class="header-anchor" href="#零散记录" aria-label="Permalink to “零散记录”">​</a></h1><p>优秀程序员的特征</p><p>对编程有激情逻</p><p>辑思维能力强懂得放弃:</p><p>先解决核心问题,部分功能选择放弃</p><p>强烈的好奇心与求知欲</p><p>坚持不懈</p><p>有企业家意识: 注重企业利益</p><p>效率,减少重复DRY: Don&#39;t Repeat Yourself.</p><p>思维缜密的技术思维 “一流程序员靠数学、二流靠算法、三流靠逻辑、四流靠SDK、五流靠 Google和StackOverflow、六流靠百度和CSDN。低端的看高端的就是黑魔法！＂简直太真实，我就是个三流半程序员</p><h1 id="工程师的十条精进原则" tabindex="-1">工程师的十条精进原则 <a class="header-anchor" href="#工程师的十条精进原则" aria-label="Permalink to “工程师的十条精进原则”">​</a></h1><p><a href="https://mp.weixin.qq.com/s?__biz=MjM5NjQ5MTI5OA==&amp;mid=2651748603&amp;idx=2&amp;sn=ef7a7d7e23e805b6246b8183b99810a0&amp;chksm=bd12a1b68a6528a0f417160e7d86f071c8dda349df2533ff95391e964a15e9ab4e9f7c8e64a7&amp;mpshare=1&amp;scene=1&amp;srcid=1209AxpEzKV70hAsnwTBCCjs&amp;sharer_sharetime=1575885755116&amp;sharer_shareid=b1f4aa4c9913bbc91a5f77aa4b83b9f7&amp;key=98a944a6bbc359822e700c115fc1039f28b732862e3ee29c1e85d7ce73eed4b9de789acd0e0c64395f4aad5c6335855364aafc0980345b3b7d1b124c9437cfc8571e9929b8a1e5af90aef6e325e88848&amp;ascene=1&amp;uin=OTcxOTExNDI0&amp;devicetype=Windows+10&amp;version=62070158&amp;lang=zh_CN&amp;exportkey=AaRzpoZhBZXTJrTZc%2Fhos9Y%3D&amp;pass_ticket=3PE3gkgIQlMEv4ktLatrhrfAu6Uo5gTeVu9usl1PJV3HdSnqiCnQQ4eeaJ9VjXF9" target="_blank" rel="noreferrer">原文出处</a> :</p><p>​ 原则 是避免错误的重要方法</p><p>很多人容易犯原则性错误, 在工作中缺乏原则的指导</p><p>一, 主人意识: <strong>认真负责</strong>, <strong>积极主动</strong></p><p>二, 时间观念: 做事有计划, 工作分主次</p><p>三, 以终为始: 先清楚目标, 然后努力实现</p><p>四, 闭环思维: 沟通有结论, 做事有结果, 问题关闭</p><p>五, 保持敬畏: 谨慎的前进, 稳健的进攻</p><p>六, 事不过二: 尽可能避免相同的错误, 做好总结反思</p><p>七, 设计优先: 有整体到局部, 避免无意义行动.</p><p>八, 产能平衡(P/PC): 相互制约才能平衡和高效, 平衡状态下的完美方案, 越到顶端</p><p>九, 善于提问: 争辩中,才能产生最好的决定和注意, 懂得如何提问</p><p>十, 空杯心态: 自我检视与反省, 做事的前提是学习和提升的心态</p>',138)])])}const g=a(p,[["render",n]]);export{b as __pageData,g as default};
